init_eqs:
timepop = 0.5;
dir = int(rand(4));
// Starting coordinates

tracex = .5;
tracey = .5;

frame_eqs:
timepop = if(below(timepop, 0), timepop=0, timepop = timepop-1/fps); //fps-independent time sync, thank you, Nitorami (martin)!
timetrig = if(above(bass, 1.65) && below(timepop, 0), timepop=0.5, timetrig);

//Changes direction with bass and 0.5 sec delay.

dir = if(equal(timepop, 0.5), int(rand(4)), dir);

tracex = if(equal(dir, 0), tracex += 0.005, tracex);
tracey = if(equal(dir, 1), tracey += 0.005, tracey);
tracex = if(equal(dir, 2), tracex -= 0.005, tracex);
tracey = if(equal(dir, 3), tracey -= 0.005, tracey);

//If it hits the border, it still continues to the opposite of border

tracex = if(above(tracex, 1.01), 0, tracex);
tracey = if(above(tracey, 1.01), 0, tracey);
tracex = if(below(tracex, -0.01), 1, tracex);
tracey = if(below(tracey, -0.01), 1, tracey);

//Transferring variables to custom shape.

q1 = tracex;
q2 = tracey;

wave_a=0;
zoom=1;
warp = 0;
monitor = dir;

//martin's Beat Code part

//dec_med = pow (0.9, 30/fps);
dec_med =  exp(-2/fps);
//dec_slow = pow (0.94, 30/fps);
dec_slow = exp(-1.8/fps);
beat = max (max (bass, mid), treb);
avg = avg*dec_slow + beat*(1-dec_slow);
is_beat = above(beat, .5+avg+peak) * above (time, t0+.2);
t0 = is_beat*time + (1-is_beat)*t0;
peak = is_beat * beat + (1-is_beat)*peak*dec_med;
index = (index + is_beat) %8;
index2 = (index2 + is_beat*bnot(index))%2;
index3 = (index3 + is_beat*bnot(index)*bnot(index2))%3;

monitor = index4;

q20 = avg;

q21 = beat;
q22 = peak;
q23 = index;
q24 = is_beat;
vol = bass + mid + treb;
q26 = max (peak,10)/20;


k1 =  is_beat*equal(index,0);
p1 =  k1*(p1+1) + (1-k1)*p1;
p2 = dec_med * p2+ (1-dec_med)*p1;
p3 = dec_slow * p3+ (1-dec_slow)*p2;

rott = p3 * $PI/2;

q5 = cos(rott)/2;
q6 = sin(rott)/2;
q7 = -q6;
q8 = q5;

q27 = 8-index;
q28 = index2;

q9 = q5*2;
//q10 = rott;

monitor = q9;

